#include <iostream>
#include <vector>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    int x;
    cin >> x;

    bool found = false;
    for (int i = 0; i < n; ++i) {
        if (a[i] == x) {
            found = true;
            break;
        }
    }

    cout << (found ? "YES" : "NO") << '\n';

    return 0;
}
